var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"이, 이것 봐. 우리한테는 말 한마디 없이 이렇게 많은 엘릭서를 만들어 뒀잖아.","JPN":"こ、これを見ろ。俺たちには内緒でこんなにたくさんのエリクサーを作っていたじゃないか。","ENG":"L-look! He's already made all this Elixir, without so much as a word to us.","TWN":"喂，你看！竟然瞞著我們做了這麼多聖水。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"주교님은 자경단 놈들을 잡으러 가셨지. 지금이 기회야.","JPN":"司教様は自警団のやつらを捕まえに行った。今がチャンスだ。","ENG":"The Bishop went after the vigilantes. Now's our chance.","TWN":"趁主教去追那些自衛隊的傢伙，就是現在！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"흐흐, 그렇게 충성했는데 고물 로켓탄 좀 불발났다고 등신 취급했겠다?","JPN":"ふん、あんなに忠誠を尽くしたのに、ポンコツのロケット弾が不発したからってクズ扱いしやがって！","ENG":"Ha! We've been nothing but loyal but he treats us like crap just because of some faulty rocket? This'll teach him!","TWN":"呵呵，原本很忠誠的，結果不說話還真當我們是笨蛋嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"젠장, 돌아와서 보관실이 텅 빈 걸 발견하고 무슨 표정을 지을지 봐야 하는데!","JPN":"ちっ、帰ってきた後に保管室ががらんとしているのを見てどんな表情をするか、見てやりたいけどな！","ENG":"Too bad we won't get to see the look on his stupid face when he finds this place empty!","TWN":"該死！真想看看他回來後，發現保管室空蕩蕩會是什麼表情。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"자자, 어서 챙겨서 여길 뜨자고! 이제 우린 떼부자야!","JPN":"さあさあ、これをまとめてさっさとここを出よう！　もう俺らは大金持ちさ！","ENG":"Come on, now. Let's grab the goods and bail! We're rich now!","TWN":"快點！東西趕快拿一拿離開吧！我們要發大財囉～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"이런, 우리 회사 재산을 마음대로 훔쳐가면 안 되지.","JPN":"おや、会社の財産を勝手に盗むのはダメだぜ。","ENG":"Tut, tut. You can't just steal company property like that.","TWN":"搞什麼，怎麼可以順手牽羊公司的財產呢！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"MOB_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"컥……! 크륵……!","JPN":"ぐっ……！　がはっ……！","ENG":"Ack...! Hngh...!","TWN":"唔……！咳咳……！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"뭐, 뭐냐! 너희들은! 여기는 마젤란 예언회의 신성한……!","JPN":"な、何だ！　お前たちは！　ここはマジェラン預言会の聖なる……！","ENG":"W-what the… Who are you?! You're trespassing on the Society's sacred-","TWN":"你…你們是誰？這裡可是麥哲倫預言會神聖的…！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"커, 커흑……. 사, 살려 줘……. 병원에…….","JPN":"が、がはっ……た、助けて……病院に……","ENG":"Ack… P-please… Take me to the hospital…","TWN":"呃嗚……救我……醫院……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"컥……. 커억……. 그만, 제발…….","JPN":"ぐあっ……ぐほっ……もう、やめてくれ……","ENG":"Ack... Hngh… Please stop…","TWN":"咳咳……嗚…住手……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"이런, 믿음으로 얼마나 버티나 보려고 했는데 금방 죽어 버리잖아.","JPN":"やれやれ、信仰心でどれだけ持ちこたえるか見てやろうとしたのに、すぐ死んじまったじゃないか。","ENG":"Oh dear. I wanted to see how long your faith would keep you alive. That was too quick.","TWN":"什麼嘛～本來想看看靠著信仰能撐多久的，結果一下就死掉啦！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MBOSS_HORIZON_NULL_NULL","text":{"KOREA":"하하. 급소 맞추는 게 버릇 되셔서 그렇죠, 대장님.","JPN":"ハハ、急所を当てるのが癖になっているからですよ、隊長。","ENG":"Haha. It's because you've made a habit of shooting them in the vitals, sir.","TWN":"哈哈。那是因為隊長你都命中要害的嘛～"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MBOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BOSS_HORIZON_NULL_NULL","text":{"KOREA":"시설에 남아 있던 자들은 모두 제압했습니다, 경호실장님.","JPN":"施設に残っていた者たちは全員制圧しました、室長。","ENG":"We've taken care of everyone in the building, ma'am.","TWN":"護衛室長，留在設施的人已經全部控制住了。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"BOSS_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SENA_HARMONY_NULL_NULL","text":{"KOREA":"후훗, 잘했어. 저런 주인도 몰라보는 못생긴 벌레들 때문에 연주하기도 피곤하거든.","JPN":"フフッ、よくやったわ。雇い主すら忘れる醜い虫けらどもは演奏の邪魔になるもの。","ENG":"Hehe, well done. It was a hassle trying to keep the music going when those ugly worms won't even recognize their master.","TWN":"唷呵～幹得好！那些連主人都不認得的走狗，搞得我連要演奏都覺得累。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"SENA_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};